using Microsoft.AspNetCore.Authorization;using Microsoft.AspNetCore.Mvc;using Microsoft.EntityFrameworkCore;using verii_metivon_api.Core.Auth;using verii_metivon_api.Core.Persistence;using verii_metivon_api.Modules.Transfers.Application.Services;using verii_metivon_api.Modules.Transfers.Domain.Entities;
namespace verii_metivon_api.Modules.Transfers.Api;[ApiController,Authorize,Route("api/transfer-orders")]public sealed class TransferOrdersController(ITransferOrderService service,MetivonDbContext db):ControllerBase{
[HttpGet]public async Task<IActionResult>List([FromQuery]TransferOrderQuery q,CancellationToken ct){var r=await service.GetPagedAsync(q,ct);return StatusCode(r.StatusCode,r);}
[HttpGet("{id:long}")]public async Task<IActionResult>Get(long id,CancellationToken ct){var e=await db.TransferOrders.AsNoTracking().Include(x=>x.Lines).FirstOrDefaultAsync(x=>x.Id==id,ct);if(e is null)return NotFound(ApiResponse<object>.Error("Transfer not found.",404));return Ok(ApiResponse<object>.Ok(new{e.TransferNumber,NumberSeriesId=(long?)null,e.FromWarehouseId,e.ToWarehouseId,e.TransferDate,e.ExpectedReceiptDate,e.Notes,Lines=e.Lines.OrderBy(x=>x.LineNumber).Select(x=>new{x.ProductId,x.UnitId,x.FromLocationId,x.ToLocationId,x.InventoryStatusId,x.InventoryLotId,x.InventorySerialId,InventorySerialIds=x.InventorySerialId.HasValue?new[]{x.InventorySerialId.Value}:Array.Empty<long>(),Quantity=x.RequestedQuantity,x.Notes})}));}
[HttpPost]public async Task<IActionResult>Create(CreateTransferRequest x,CancellationToken ct){var r=await service.CreateAsync(x,ct);return StatusCode(r.StatusCode,r);}
[HttpPut("{id:long}")]public async Task<IActionResult>Update(long id,CreateTransferRequest r,CancellationToken ct){var e=await db.TransferOrders.Include(x=>x.Lines).FirstOrDefaultAsync(x=>x.Id==id,ct);if(e is null)return NotFound(ApiResponse<object>.Error("Transfer not found.",404));if(e.Status!=TransferOrderStatus.Draft)return Conflict(ApiResponse<object>.Error("Only draft transfers can be edited.",409));if(r.FromWarehouseId==r.ToWarehouseId||r.Lines.Count==0)return BadRequest(ApiResponse<object>.Error("Different warehouses and at least one line are required.",400));e.TransferNumber=string.IsNullOrWhiteSpace(r.TransferNumber)?e.TransferNumber:r.TransferNumber.Trim().ToUpperInvariant();e.FromWarehouseId=r.FromWarehouseId;e.ToWarehouseId=r.ToWarehouseId;e.TransferDate=r.TransferDate;e.ExpectedReceiptDate=r.ExpectedReceiptDate;e.Notes=r.Notes?.Trim();db.TransferOrderLines.RemoveRange(e.Lines);e.Lines=[];var n=0;foreach(var l in r.Lines){if(l.Quantity<=0)return BadRequest(ApiResponse<object>.Error("Transfer quantity must be positive.",400));var serialIds=(l.InventorySerialIds??[]).Append(l.InventorySerialId??0).Where(x=>x>0).Distinct().ToArray();if(serialIds.Length>1&&l.Quantity!=serialIds.Length)return BadRequest(ApiResponse<object>.Error("Selected serial count must match transfer quantity.",400));if(serialIds.Length==0)e.Lines.Add(new(){LineNumber=++n,ProductId=l.ProductId,UnitId=l.UnitId,FromLocationId=l.FromLocationId,ToLocationId=l.ToLocationId,InventoryStatusId=l.InventoryStatusId??0,InventoryLotId=l.InventoryLotId,RequestedQuantity=l.Quantity,Notes=l.Notes?.Trim()});else foreach(var serialId in serialIds)e.Lines.Add(new(){LineNumber=++n,ProductId=l.ProductId,UnitId=l.UnitId,FromLocationId=l.FromLocationId,ToLocationId=l.ToLocationId,InventoryStatusId=l.InventoryStatusId??0,InventoryLotId=l.InventoryLotId,InventorySerialId=serialId,RequestedQuantity=1,Notes=l.Notes?.Trim()});}await db.SaveChangesAsync(ct);return Ok(ApiResponse<object>.Ok(new{e.Id}));}
[HttpPost("{id:long}/ship")]public async Task<IActionResult>Ship(long id,CancellationToken ct){var r=await service.ShipAsync(id,ct);return StatusCode(r.StatusCode,r);}[HttpPost("{id:long}/receive")]public async Task<IActionResult>Receive(long id,CancellationToken ct){var r=await service.ReceiveAsync(id,ct);return StatusCode(r.StatusCode,r);}[HttpDelete("{id:long}")]public async Task<IActionResult>Delete(long id,CancellationToken ct){var e=await db.TransferOrders.Include(x=>x.Lines).FirstOrDefaultAsync(x=>x.Id==id,ct);if(e is null)return NotFound(ApiResponse<object>.Error("Transfer not found.",404));if(e.Status!=TransferOrderStatus.Draft)return Conflict(ApiResponse<object>.Error("Only draft transfers can be deleted.",409));db.TransferOrders.Remove(e);await db.SaveChangesAsync(ct);return Ok(ApiResponse<object>.Ok(new{e.Id}));}}
